INSERT OR IGNORE INTO 'messages'('id', 'chat_id', 'role', 'content', 'model', 'metadata', 'created_at') VALUES (238, 62, 'assistant', replace('Entendido. Cambio a modo writer. Estoy listo para ayudarte con:\n\n- **Escritura creativa** — historias, poesía, diálogos, guiones\n- **Contenido editorial** — artículos, ensayos, análisis\n- **Copywriting** — textos publicitarios, descripciones de productos\n- **Edición y revisión** — mejorar textos, pulir prosa, corregir tono\n- **Brainstorming narrativo** — desarrollar tramas, personajes, conceptos\n\n¿Qué necesitas escribir? Dame el contexto y te doy mi mejor versión.','\n', char(10)), 'anthropic/claude-haiku-4-5-20251001', '{}', '2026-05-08 03:05:27');
INSERT OR IGNORE INTO 'messages'('id', 'chat_id', 'role', 'content', 'model', 'metadata', 'created_at') VALUES (239, 62, 'user', 'como funcionan tus skills', 'anthropic/claude-haiku-4-5-20251001', '{}', '2026-05-08 03:05:34');
INSERT OR IGNORE INTO 'messages'('id', 'chat_id', 'role', 'content', 'model', 'metadata', 'created_at') VALUES (93, 15, 'assistant', 'Voy a crear el archivo test.txt con ese contenido.El sandbox no está disponible en este momento (error de conexión). No puedo crear el archivo en este instante. Intenta nuevamente en unos momentos o verifica si el servicio de sandbox está activo.', 'anthropic/claude-haiku-4-5-20251001', '{"toolCalls":[{"name":"file_write","args":{"content":"hello world","path":"test.txt"},"result":"error: sandbox unavailable: create sandbox for chat 15: opensandbox create: opensandbox: create sandbox: opensandbox: do request: Post \"http://localhost:8080/v1/sandboxes\": dial tcp [::1]:8080: connect: connection refused","error":true}],"artifacts":[{"path":"test.txt","language":"text","content":"hello world"}]}', '2026-05-07 17:10:18');
