INSERT OR IGNORE INTO 'messages'('id', 'chat_id', 'role', 'content', 'model', 'metadata', 'created_at') VALUES (120, 37, 'assistant', replace('Veo que ya mencionaste que crearás un archivo. ¿Deseas que yo lo cree en el sandbox, o ya lo hiciste por tu cuenta?\n\nSi quieres que lo haga, puedo crear el archivo `hello.txt` con el contenido "Hola Mundo" ahora mismo:Perfecto. El archivo `hello.txt` ha sido creado exitosamente con el contenido "Hola Mundo" (10 bytes).\n\n¿Hay algo más que quieras hacer con este archivo?','\n', char(10)), 'anthropic/claude-haiku-4-5-20251001', '{}', '2026-05-07 18:46:10');
INSERT OR IGNORE INTO 'messages'('id', 'chat_id', 'role', 'content', 'model', 'metadata', 'created_at') VALUES (121, 38, 'user', '"Necesito crear un archivo de configuración"', 'anthropic/claude-haiku-4-5-20251001', '{}', '2026-05-07 18:56:49');
INSERT OR IGNORE INTO 'messages'('id', 'chat_id', 'role', 'content', 'model', 'metadata', 'created_at') VALUES (122, 38, 'assistant', replace('Entiendo que necesitas crear un archivo de configuración. Para ayudarte de la mejor manera, necesito algunos detalles:\n\n1. **¿Qué tipo de configuración?** (por ejemplo: JSON, YAML, INI, ENV, XML, etc.)\n2. **¿Para qué proyecto o aplicación?** (por ejemplo: Node.js, Python, base de datos, servidor web, etc.)\n3. **¿Qué parámetros o valores debe contener?** (o ¿tienes un ejemplo o plantilla?)\n4. **¿Dónde lo necesitas guardar?** (ruta del archivo)\n\nCon esta información podré crear el archivo exactamente como lo necesitas.','\n', char(10)), 'anthropic/claude-haiku-4-5-20251001', '{}', '2026-05-07 18:56:54');
INSERT OR IGNORE INTO 'messages'('id', 'chat_id', 'role', 'content', 'model', 'metadata', 'created_at') VALUES (123, 39, 'user', '"Necesito crear un archivo de configuración".', 'anthropic/claude-haiku-4-5-20251001', '{}', '2026-05-07 18:59:13');
INSERT OR IGNORE INTO 'messages'('id', 'chat_id', 'role', 'content', 'model', 'metadata', 'created_at') VALUES (124, 39, 'assistant', replace('Entiendo que necesitas crear un archivo de configuración. Para ayudarte de la mejor manera, necesito algunos detalles:\n\n1. **¿Qué tipo de configuración?** (por ejemplo: JSON, YAML, .env, INI, XML, etc.)\n2. **¿Para qué aplicación o propósito?** (backend, frontend, base de datos, etc.)\n3. **¿Qué parámetros o valores debe contener?**\n\nCon esta información podré crear exactamente lo que necesitas.','\n', char(10)), 'anthropic/claude-haiku-4-5-20251001', '{}', '2026-05-07 18:59:17');
INSERT OR IGNORE INTO 'messages'('id', 'chat_id', 'role', 'content', 'model', 'metadata', 'created_at') VALUES (125, 43, 'user', 'Explica en 3 frases qué es Server-Sent Events.', 'anthropic/claude-haiku-4-5-20251001', '{}', '2026-05-07 23:15:19');
INSERT OR IGNORE INTO 'messages'('id', 'chat_id', 'role', 'content', 'model', 'metadata', 'created_at') VALUES (126, 43, 'assistant', '**Server-Sent Events (SSE)** es un estándar web que permite que un servidor envíe datos hacia un cliente de forma unidireccional y en tiempo real, sin que el cliente tenga que solicitar constantemente nueva información. A diferencia de WebSocket, SSE utiliza HTTP estándar y es más simple de implementar, ideal para casos donde solo el servidor necesita enviar actualizaciones (notificaciones, feeds en vivo, actualizaciones de estado). La conexión se mantiene abierta y el servidor puede "empujar" eventos al cliente automáticamente siempre que sea necesario.', 'anthropic/claude-haiku-4-5-20251001', '{}', '2026-05-07 23:15:24');
INSERT OR IGNORE INTO 'messages'('id', 'chat_id', 'role', 'content', 'model', 'metadata', 'created_at') VALUES (127, 43, 'user', 'Crea un archivo hello.txt con el texto hola mundo usando file_write."', 'anthropic/claude-haiku-4-5-20251001', '{}', '2026-05-07 23:15:40');
