INSERT OR IGNORE INTO 'messages'('id', 'chat_id', 'role', 'content', 'model', 'metadata', 'created_at') VALUES (131, 45, 'assistant', replace('Voy a crear el archivo hello.txt con el contenido "hola mundo".El servidor sandbox no está disponible en este momento. No puedo crear el archivo porque la conexión al entorno aislado ha fallado. Esto es un problema técnico temporal con la infraestructura backend.\n\nIntenta de nuevo en unos momentos, o si necesitas una alternativa, puedo ayudarte con instrucciones sobre cómo crear el archivo manualmente en tu sistema local.','\n', char(10)), 'anthropic/claude-haiku-4-5-20251001', '{"toolCalls":[{"name":"file_write","args":{"content":"hola mundo","path":"hello.txt"},"result":"error: sandbox unavailable: create sandbox for chat 45: opensandbox create: opensandbox: create sandbox: opensandbox: do request: Post \"http://localhost:8080/v1/sandboxes\": dial tcp [::1]:8080: connect: connection refused","error":true}],"artifacts":[{"path":"hello.txt","language":"text","content":"hola mundo"}]}', '2026-05-07 23:38:06');
INSERT OR IGNORE INTO 'messages'('id', 'chat_id', 'role', 'content', 'model', 'metadata', 'created_at') VALUES (132, 46, 'user', '"Explica en 3 frases qué es Server-Sent Events."', 'anthropic/claude-haiku-4-5-20251001', '{}', '2026-05-07 23:40:45');
INSERT OR IGNORE INTO 'messages'('id', 'chat_id', 'role', 'content', 'model', 'metadata', 'created_at') VALUES (133, 46, 'assistant', 'Server-Sent Events (SSE) es un estándar web que permite que un servidor envíe datos al cliente de forma unidireccional y automática a través de una conexión HTTP persistente. El cliente establece una conexión y recibe actualizaciones en tiempo real sin necesidad de hacer solicitudes repetidas (polling). Es ideal para casos como notificaciones, feeds en vivo o actualizaciones de estado, aunque solo funciona en una dirección: del servidor al cliente.', 'anthropic/claude-haiku-4-5-20251001', '{}', '2026-05-07 23:40:49');
