INSERT OR IGNORE INTO 'messages'('id', 'chat_id', 'role', 'content', 'model', 'metadata', 'created_at') VALUES (143, 46, 'user', 'Necesita una tool ask_user(prompt, choices) que llame a gate.Wait() con Kind: InterruptKindQuestion.', 'anthropic/claude-haiku-4-5-20251001', '{}', '2026-05-07 23:44:20');
INSERT OR IGNORE INTO 'messages'('id', 'chat_id', 'role', 'content', 'model', 'metadata', 'created_at') VALUES (144, 46, 'assistant', replace('No tengo acceso a una tool `ask_user()` en mi conjunto de herramientas disponibles. Las herramientas que tengo son:\n\n- **memory-operations** — leer y escribir memoria persistente\n- **skills-operations** — gestionar skills\n- **create-checkpoint** — crear puntos de guardado\n- **file_read/file_write** — manipular archivos\n- **bash/code_interpreter** — ejecutar código\n- **dispatch-subagents** — crear subagentes paralelos\n\nPara implementar una funcionalidad que llame a `gate.Wait()` con `Kind: InterruptKindQuestion`, necesitarías:\n\n1. **Cargar una skill** que exponga esa funcionalidad (si está disponible en el backend)\n2. **Solicitar a los desarrolladores** que añadan una nueva tool al harness-sdk\n\n¿Quieres que verifique qué skills están disponibles en el backend que podrían permitir interrupciones interactivas?','\n', char(10)), 'anthropic/claude-haiku-4-5-20251001', '{}', '2026-05-07 23:44:25');
INSERT OR IGNORE INTO 'messages'('id', 'chat_id', 'role', 'content', 'model', 'metadata', 'created_at') VALUES (145, 46, 'user', '"Pregúntame qué framework prefiero antes de generar código: Go o Rust."', 'anthropic/claude-haiku-4-5-20251001', '{}', '2026-05-07 23:44:49');
INSERT OR IGNORE INTO 'messages'('id', 'chat_id', 'role', 'content', 'model', 'metadata', 'created_at') VALUES (146, 46, 'assistant', '¿Cuál de estos frameworks prefieres para que genere el código: **Go** o **Rust**?', 'anthropic/claude-haiku-4-5-20251001', '{}', '2026-05-07 23:44:52');
INSERT OR IGNORE INTO 'messages'('id', 'chat_id', 'role', 'content', 'model', 'metadata', 'created_at') VALUES (147, 46, 'user', replace('"Renderiza una PatientChart para Jane Doe, 34 años, con presión 120/80."\n"Muestra una MedicationList con Aspirina 100mg cada 8h y Paracetamol 500mg cada 6h."','\n', char(10)), 'anthropic/claude-haiku-4-5-20251001', '{}', '2026-05-07 23:45:19');
INSERT OR IGNORE INTO 'messages'('id', 'chat_id', 'role', 'content', 'model', 'metadata', 'created_at') VALUES (148, 46, 'assistant', 'Voy a crear un componente React que renderice una tabla de paciente con su información clínica y lista de medicamentos.He creado un componente React que muestra la información del paciente Jane Doe (34 años, presión 120/80) y su lista de medicamentos (Aspirina 100mg cada 8h y Paracetamol 500mg cada 6h) en una tabla organizada.', 'anthropic/claude-haiku-4-5-20251001', '{"toolCalls":[{"name":"file_write","args":{"content":"import React from ''react'';\n\nexport default function PatientChart() {\n  const patient = {\n    name: ''Jane Doe'',\n    age: 34,\n    bloodPressure: ''120/80''\n  };\n\n  const medications = [\n    { name: ''Aspirina'', dose: ''100mg'', frequency: ''cada 8h'' },\n    { name: ''Paracetamol'', dose: ''500mg'', frequency: ''cada 6h'' }\n  ];\n\n  return (\n    \u003cdiv style={{ fontFamily: ''Arial, sans-serif'', padding: ''20px'', maxWidth: ''600px'', margin: ''0 auto'' }}\u003e\n      \u003ch1\u003eHistorial del Paciente\u003c/h1\u003e\n      \n      \u003cdiv style={{ border: ''1px solid #ccc'', padding: ''15px'', marginBottom: ''20px'', borderRadius: ''5px'', backgroundColor: ''#f9f9f9'' }}\u003e\n        \u003ch2 style={{ marginTop: 0 }}\u003eInformación del Paciente\u003c/h2\u003e\n        \u003cp\u003e\u003cstrong\u003eNombre:\u003c/strong\u003e {patient.name}\u003c/p\u003e\n        \u003cp\u003e\u003cstrong\u003eEdad:\u003c/strong\u003e {patient.age} años\u003c/p\u003e\n        \u003cp\u003e\u003cstrong\u003ePresión Arterial:\u003c/strong\u003e {patient.bloodPressure} mmHg\u003c/p\u003e\n      \u003c/div\u003e\n\n      \u003cdiv style={{ border: ''1px solid #ccc'', padding: ''15px'', borderRadius: ''5px'', backgroundColor: ''#f9f9f9'' }}\u003e\n        \u003ch2 style={{ marginTop: 0 }}\u003eMedicamentos\u003c/h2\u003e\n        \u003ctable style={{ width: ''100%'', borderCollapse: ''collapse'' }}\u003e\n          \u003cthead\u003e\n            \u003ctr style={{ borderBottom: ''2px solid #333'' }}\u003e\n              \u003cth style={{ textAlign: ''left'', padding: ''8px'' }}\u003eMedicamento\u003c/th\u003e\n              \u003cth style={{ textAlign: ''left'', padding: ''8px'' }}\u003eDosis\u003c/th\u003e\n              \u003cth style={{ textAlign: ''left'', padding: ''8px'' }}\u003eFrecuencia\u003c/th\u003e\n            \u003c/tr\u003e\n          \u003c/thead\u003e\n          \u003ctbody\u003e\n            {medications.map((med, idx) =\u003e (\n              \u003ctr key={idx} style={{ borderBottom: ''1px solid #ddd'' }}\u003e\n                \u003ctd style={{ padding: ''8px'' }}\u003e{med.name}\u003c/td\u003e\n                \u003ctd style={{ padding: ''8px'' }}\u003e{med.dose}\u003c/td\u003e\n                \u003ctd style={{ padding: ''8px'' }}\u003e{med.frequency}\u003c/td\u003e\n              \u003c/tr\u003e\n            ))}\n          \u003c/tbody\u003e\n        \u003c/table\u003e\n      \u003c/div\u003e\n    \u003c/div\u003e\n  );\n}","path":"/PatientChart.jsx"},"result":"file written: /PatientChart.jsx (1914 bytes)"}],"artifacts":[{"path":"/PatientChart.jsx","language":"jsx","content":"import React from ''react'';\n\nexport default function PatientChart() {\n  const patient = {\n    name: ''Jane Doe'',\n    age: 34,\n    bloodPressure: ''120/80''\n  };\n\n  const medications = [\n    { name: ''Aspirina'', dose: ''100mg'', frequency: ''cada 8h'' },\n    { name: ''Paracetamol'', dose: ''500mg'', frequency: ''cada 6h'' }\n  ];\n\n  return (\n    \u003cdiv style={{ fontFamily: ''Arial, sans-serif'', padding: ''20px'', maxWidth: ''600px'', margin: ''0 auto'' }}\u003e\n      \u003ch1\u003eHistorial del Paciente\u003c/h1\u003e\n      \n      \u003cdiv style={{ border: ''1px solid #ccc'', padding: ''15px'', marginBottom: ''20px'', borderRadius: ''5px'', backgroundColor: ''#f9f9f9'' }}\u003e\n        \u003ch2 style={{ marginTop: 0 }}\u003eInformación del Paciente\u003c/h2\u003e\n        \u003cp\u003e\u003cstrong\u003eNombre:\u003c/strong\u003e {patient.name}\u003c/p\u003e\n        \u003cp\u003e\u003cstrong\u003eEdad:\u003c/strong\u003e {patient.age} años\u003c/p\u003e\n        \u003cp\u003e\u003cstrong\u003ePresión Arterial:\u003c/strong\u003e {patient.bloodPressure} mmHg\u003c/p\u003e\n      \u003c/div\u003e\n\n      \u003cdiv style={{ border: ''1px solid #ccc'', padding: ''15px'', borderRadius: ''5px'', backgroundColor: ''#f9f9f9'' }}\u003e\n        \u003ch2 style={{ marginTop: 0 }}\u003eMedicamentos\u003c/h2\u003e\n        \u003ctable style={{ width: ''100%'', borderCollapse: ''collapse'' }}\u003e\n          \u003cthead\u003e\n            \u003ctr style={{ borderBottom: ''2px solid #333'' }}\u003e\n              \u003cth style={{ textAlign: ''left'', padding: ''8px'' }}\u003eMedicamento\u003c/th\u003e\n              \u003cth style={{ textAlign: ''left'', padding: ''8px'' }}\u003eDosis\u003c/th\u003e\n              \u003cth style={{ textAlign: ''left'', padding: ''8px'' }}\u003eFrecuencia\u003c/th\u003e\n            \u003c/tr\u003e\n          \u003c/thead\u003e\n          \u003ctbody\u003e\n            {medications.map((med, idx) =\u003e (\n              \u003ctr key={idx} style={{ borderBottom: ''1px solid #ddd'' }}\u003e\n                \u003ctd style={{ padding: ''8px'' }}\u003e{med.name}\u003c/td\u003e\n                \u003ctd style={{ padding: ''8px'' }}\u003e{med.dose}\u003c/td\u003e\n                \u003ctd style={{ padding: ''8px'' }}\u003e{med.frequency}\u003c/td\u003e\n              \u003c/tr\u003e\n            ))}\n          \u003c/tbody\u003e\n        \u003c/table\u003e\n      \u003c/div\u003e\n    \u003c/div\u003e\n  );\n}"}]}', '2026-05-07 23:45:47');
INSERT OR IGNORE INTO 'messages'('id', 'chat_id', 'role', 'content', 'model', 'metadata', 'created_at') VALUES (149, 47, 'user', '"Necesito que el usuario complete un formulario de admisión hospitalaria con nombre, edad y alergias."', 'anthropic/claude-haiku-4-5-20251001', '{}', '2026-05-07 23:46:47');
INSERT OR IGNORE INTO 'messages'('id', 'chat_id', 'role', 'content', 'model', 'metadata', 'created_at') VALUES (150, 47, 'assistant', replace('Voy a crear un formulario de admisión hospitalaria interactivo que se adapte a tus necesidades.He creado un formulario de admisión hospitalaria completo que incluye:\n\n**Características:**\n- ✓ Campos para nombre, edad y alergias (todos obligatorios)\n- ✓ Validación en tiempo real que muestra errores mientras escribes\n- ✓ Diseño profesional con colores médicos\n- ✓ Mensaje de confirmación cuando se completa correctamente\n- ✓ Los datos se guardan en localStorage para referencia\n- ✓ Botón para limpiar el formulario\n- ✓ Responsivo (funciona en móvil y escritorio)\n\nEl formulario está listo para usar. Los datos ingresados se registran automáticamente cuando valida correctamente. ¿Necesitas agregar más campos o alguna funcionalidad adicional?','\n', char(10)), 'anthropic/claude-haiku-4-5-20251001', '{"toolCalls":[{"name":"file_write","args":{"content":"\u003c!DOCTYPE html\u003e\n\u003chtml lang=\"es\"\u003e\n\u003chead\u003e\n    \u003cmeta charset=\"UTF-8\"\u003e\n    \u003cmeta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\"\u003e\n    \u003ctitle\u003eFormulario de Admisión Hospitalaria\u003c/title\u003e\n    \u003cstyle\u003e\n        * {\n            margin: 0;\n            padding: 0;\n            box-sizing: border-box;\n        }\n        \n        body {\n            font-family: ''Segoe UI'', Tahoma, Geneva, Verdana, sans-serif;\n            background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);\n            min-height: 100vh;\n            display: flex;\n            justify-content: center;\n            align-items: center;\n            padding: 20px;\n        }\n        \n        .container {\n            background: white;\n            border-radius: 10px;\n            box-shadow: 0 10px 40px rgba(0, 0, 0, 0.2);\n            max-width: 600px;\n            width: 100%;\n            padding: 40px;\n        }\n        \n        .header {\n            text-align: center;\n            margin-bottom: 30px;\n            border-bottom: 3px solid #667eea;\n            padding-bottom: 20px;\n        }\n        \n        .header h1 {\n            color: #333;\n            font-size: 28px;\n            margin-bottom: 5px;\n        }\n        \n        .header p {\n            color: #666;\n            font-size: 14px;\n        }\n        \n        .form-group {\n            margin-bottom: 25px;\n        }\n        \n        label {\n            display: block;\n            margin-bottom: 8px;\n            color: #333;\n            font-weight: 600;\n            font-size: 14px;\n        }\n        \n        .required {\n            color: #e74c3c;\n        }\n        \n        input[type=\"text\"],\n        input[type=\"number\"],\n        textarea {\n            width: 100%;\n            padding: 12px;\n            border: 2px solid #ddd;\n            border-radius: 5px;\n            font-size: 14px;\n            font-family: inherit;\n            transition: border-color 0.3s;\n        }\n        \n        input[type=\"text\"]:focus,\n        input[type=\"number\"]:focus,\n        textarea:focus {\n            outline: none;\n            border-color: #667eea;\n            background-color: #f8f9ff;\n        }\n        \n        textarea {\n            resize: vertical;\n            min-height: 100px;\n        }\n        \n        .input-group {\n            display: grid;\n            grid-template-columns: 1fr 1fr;\n            gap: 20px;\n        }\n        \n        .button-group {\n            display: flex;\n            gap: 10px;\n            margin-top: 30px;\n        }\n        \n        button {\n            flex: 1;\n            padding: 12px;\n            border: none;\n            border-radius: 5px;\n            font-size: 16px;\n            font-weight: 600;\n            cursor: pointer;\n            transition: all 0.3s;\n        }\n        \n        .btn-submit {\n            background: #667eea;\n            color: white;\n        }\n        \n        .btn-submit:hover {\n            background: #5568d3;\n            transform: translateY(-2px);\n            box-shadow: 0 5px 15px rgba(102, 126, 234, 0.4);\n        }\n        \n        .btn-reset {\n            background: #e8e8e8;\n            color: #333;\n        }\n        \n        .btn-reset:hover {\n            background: #d0d0d0;\n        }\n        \n        .error {\n            color: #e74c3c;\n            font-size: 12px;\n            margin-top: 5px;\n            display: none;\n        }\n        \n        .success {\n            display: none;\n            background: #d4edda;\n            border: 2px solid #28a745;\n            color: #155724;\n            padding: 15px;\n            border-radius: 5px;\n            margin-top: 20px;\n        }\n        \n        .success.show {\n            display: block;\n        }\n        \n        .info-box {\n            background: #e7f3ff;\n            border-left: 4px solid #667eea;\n            padding: 12px;\n            margin-bottom: 20px;\n            border-radius: 4px;\n            font-size: 13px;\n            color: #333;\n        }\n    \u003c/style\u003e\n\u003c/head\u003e\n\u003cbody\u003e\n    \u003cdiv class=\"container\"\u003e\n        \u003cdiv class=\"header\"\u003e\n            \u003ch1\u003e🏥 Admisión Hospitalaria\u003c/h1\u003e\n            \u003cp\u003ePor favor, completa el formulario con la información del paciente\u003c/p\u003e\n        \u003c/div\u003e\n        \n        \u003cdiv class=\"info-box\"\u003e\n            \u003cstrong\u003eNota:\u003c/strong\u003e Los campos marcados con * son obligatorios\n        \u003c/div\u003e\n        \n        \u003cform id=\"formularioAdmision\" novalidate\u003e\n            \u003c!-- Nombre --\u003e\n            \u003cdiv class=\"form-group\"\u003e\n                \u003clabel for=\"nombre\"\u003e\n                    Nombre Completo \u003cspan class=\"required\"\u003e*\u003c/span\u003e\n                \u003c/label\u003e\n                \u003cinput \n                    type=\"text\" \n                    id=\"nombre\" \n                    name=\"nombre\" \n                    placeholder=\"Ej: Juan Pérez García\"\n                    required\n                \u003e\n                \u003cdiv class=\"error\" id=\"errorNombre\"\u003eEl nombre es obligatorio\u003c/div\u003e\n            \u003c/div\u003e\n            \n            \u003c!-- Edad --\u003e\n            \u003cdiv class=\"form-group\"\u003e\n                \u003clabel for=\"edad\"\u003e\n                    Edad \u003cspan class=\"required\"\u003e*\u003c/span\u003e\n                \u003c/label\u003e\n                \u003cinput \n                    type=\"number\" \n                    id=\"edad\" \n                    name=\"edad\" \n                    placeholder=\"Ej: 35\"\n                    min=\"0\"\n                    max=\"150\"\n                    required\n                \u003e\n                \u003cdiv class=\"error\" id=\"errorEdad\"\u003ePor favor ingresa una edad válida (0-150)\u003c/div\u003e\n            \u003c/div\u003e\n            \n            \u003c!-- Alergias --\u003e\n            \u003cdiv class=\"form-group\"\u003e\n                \u003clabel for=\"alergias\"\u003e\n                    Alergias Conocidas \u003cspan class=\"required\"\u003e*\u003c/span\u003e\n                \u003c/label\u003e\n                \u003ctextarea \n                    id=\"alergias\" \n                    name=\"alergias\" \n                    placeholder=\"Ej: Penicilina, Mariscos, Polen\u0026#10;Si no tiene alergias conocidas, escribe ''Ninguna''\"\n                    required\n                \u003e\u003c/textarea\u003e\n                \u003cdiv class=\"error\" id=\"errorAlergias\"\u003ePor favor especifica las alergias o escribe ''Ninguna''\u003c/div\u003e\n            \u003c/div\u003e\n            \n            \u003c!-- Botones --\u003e\n            \u003cdiv class=\"button-group\"\u003e\n                \u003cbutton type=\"submit\" class=\"btn-submit\"\u003eEnviar Formulario\u003c/button\u003e\n                \u003cbutton type=\"reset\" class=\"btn-reset\"\u003eLimpiar\u003c/button\u003e\n            \u003c/div\u003e\n            \n            \u003c!-- Mensaje de éxito --\u003e\n            \u003cdiv class=\"success\" id=\"mensajeExito\"\u003e\n                ✓ Formulario enviado correctamente. Los datos del paciente han sido registrados.\n            \u003c/div\u003e\n        \u003c/form\u003e\n    \u003c/div\u003e\n    \n    \u003cscript\u003e\n        const formulario = document.getElementById(''formularioAdmision'');\n        const campos = {\n            nombre: document.getElementById(''nombre''),\n            edad: document.getElementById(''edad''),\n            alergias: document.getElementById(''alergias'')\n        };\n        \n        const errores = {\n            nombre: document.getElementById(''errorNombre''),\n            edad: document.getElementById(''errorEdad''),\n            alergias: document.getElementById(''errorAlergias'')\n        };\n        \n        const mensajeExito = document.getElementById(''mensajeExito'');\n        \n        // Validación en tiempo real\n        campos.nombre.addEventListener(''input'', function() {\n            if (this.value.trim().length \u003e 0) {\n                errores.nombre.style.display = ''none'';\n            }\n        });\n        \n        campos.edad.addEventListener(''input'', function() {\n            const edad = parseInt(this.value);\n            if (!isNaN(edad) \u0026\u0026 edad \u003e= 0 \u0026\u0026 edad \u003c= 150) {\n                errores.edad.style.display = ''none'';\n            }\n        });\n        \n        campos.alergias.addEventListener(''input'', function() {\n            if (this.value.trim().length \u003e 0) {\n                errores.alergias.style.display = ''none'';\n            }\n        });\n        \n        // Validación del formulario al enviar\n        formulario.addEventListener(''submit'', function(e) {\n            e.preventDefault();\n            \n            let esValido = true;\n            mensajeExito.classList.remove(''show'');\n            \n            // Validar nombre\n            if (campos.nombre.value.trim().length === 0) {\n                errores.nombre.style.display = ''block'';\n                esValido = false;\n            }\n            \n            // Validar edad\n            const edad = parseInt(campos.edad.value);\n            if (isNaN(edad) || edad \u003c 0 || edad \u003e 150) {\n                errores.edad.style.display = ''block'';\n                esValido = false;\n            }\n            \n            // Validar alergias\n            if (campos.alergias.value.trim().length === 0) {\n                errores.alergias.style.display = ''block'';\n                esValido = false;\n            }\n            \n            // Si es válido, mostrar éxito y guardar datos\n            if (esValido) {\n                const datos = {\n                    nombre: campos.nombre.value.trim(),\n                    edad: parseInt(campos.edad.value),\n                    alergias: campos.alergias.value.trim(),\n                    fechaAdmision: new Date().toLocaleString(''es-ES'')\n                };\n                \n                console.log(''Datos registrados:'', datos);\n                \n                // Guardar en localStorage para referencia\n                localStorage.setItem(''ultimaAdmision'', JSON.stringify(datos));\n                \n                // Mostrar mensaje de éxito\n                mensajeExito.classList.add(''show'');\n                \n                // Opcional: limpiar el formulario después de 2 segundos\n                setTimeout(() =\u003e {\n                    formulario.reset();\n                    mensajeExito.classList.remove(''show'');\n                }, 3000);\n            }\n        });\n    \u003c/script\u003e\n\u003c/body\u003e\n\u003c/html\u003e","path":"/workspace/formulario_admision.html"},"result":"file written: /workspace/formulario_admision.html (9886 bytes)"}],"artifacts":[{"path":"/workspace/formulario_admision.html","language":"html","content":"\u003c!DOCTYPE html\u003e\n\u003chtml lang=\"es\"\u003e\n\u003chead\u003e\n    \u003cmeta charset=\"UTF-8\"\u003e\n    \u003cmeta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\"\u003e\n    \u003ctitle\u003eFormulario de Admisión Hospitalaria\u003c/title\u003e\n    \u003cstyle\u003e\n        * {\n            margin: 0;\n            padding: 0;\n            box-sizing: border-box;\n        }\n        \n        body {\n            font-family: ''Segoe UI'', Tahoma, Geneva, Verdana, sans-serif;\n            background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);\n            min-height: 100vh;\n            display: flex;\n            justify-content: center;\n            align-items: center;\n            padding: 20px;\n        }\n        \n        .container {\n            background: white;\n            border-radius: 10px;\n            box-shadow: 0 10px 40px rgba(0, 0, 0, 0.2);\n            max-width: 600px;\n            width: 100%;\n            padding: 40px;\n        }\n        \n        .header {\n            text-align: center;\n            margin-bottom: 30px;\n            border-bottom: 3px solid #667eea;\n            padding-bottom: 20px;\n        }\n        \n        .header h1 {\n            color: #333;\n            font-size: 28px;\n            margin-bottom: 5px;\n        }\n        \n        .header p {\n            color: #666;\n            font-size: 14px;\n        }\n        \n        .form-group {\n            margin-bottom: 25px;\n        }\n        \n        label {\n            display: block;\n            margin-bottom: 8px;\n            color: #333;\n            font-weight: 600;\n            font-size: 14px;\n        }\n        \n        .required {\n            color: #e74c3c;\n        }\n        \n        input[type=\"text\"],\n        input[type=\"number\"],\n        textarea {\n            width: 100%;\n            padding: 12px;\n            border: 2px solid #ddd;\n            border-radius: 5px;\n            font-size: 14px;\n            font-family: inherit;\n            transition: border-color 0.3s;\n        }\n        \n        input[type=\"text\"]:focus,\n        input[type=\"number\"]:focus,\n        textarea:focus {\n            outline: none;\n            border-color: #667eea;\n            background-color: #f8f9ff;\n        }\n        \n        textarea {\n            resize: vertical;\n            min-height: 100px;\n        }\n        \n        .input-group {\n            display: grid;\n            grid-template-columns: 1fr 1fr;\n            gap: 20px;\n        }\n        \n        .button-group {\n            display: flex;\n            gap: 10px;\n            margin-top: 30px;\n        }\n        \n        button {\n            flex: 1;\n            padding: 12px;\n            border: none;\n            border-radius: 5px;\n            font-size: 16px;\n            font-weight: 600;\n            cursor: pointer;\n            transition: all 0.3s;\n        }\n        \n        .btn-submit {\n            background: #667eea;\n            color: white;\n        }\n        \n        .btn-submit:hover {\n            background: #5568d3;\n            transform: translateY(-2px);\n            box-shadow: 0 5px 15px rgba(102, 126, 234, 0.4);\n        }\n        \n        .btn-reset {\n            background: #e8e8e8;\n            color: #333;\n        }\n        \n        .btn-reset:hover {\n            background: #d0d0d0;\n        }\n        \n        .error {\n            color: #e74c3c;\n            font-size: 12px;\n            margin-top: 5px;\n            display: none;\n        }\n        \n        .success {\n            display: none;\n            background: #d4edda;\n            border: 2px solid #28a745;\n            color: #155724;\n            padding: 15px;\n            border-radius: 5px;\n            margin-top: 20px;\n        }\n        \n        .success.show {\n            display: block;\n        }\n        \n        .info-box {\n            background: #e7f3ff;\n            border-left: 4px solid #667eea;\n            padding: 12px;\n            margin-bottom: 20px;\n            border-radius: 4px;\n            font-size: 13px;\n            color: #333;\n        }\n    \u003c/style\u003e\n\u003c/head\u003e\n\u003cbody\u003e\n    \u003cdiv class=\"container\"\u003e\n        \u003cdiv class=\"header\"\u003e\n            \u003ch1\u003e🏥 Admisión Hospitalaria\u003c/h1\u003e\n            \u003cp\u003ePor favor, completa el formulario con la información del paciente\u003c/p\u003e\n        \u003c/div\u003e\n        \n        \u003cdiv class=\"info-box\"\u003e\n            \u003cstrong\u003eNota:\u003c/strong\u003e Los campos marcados con * son obligatorios\n        \u003c/div\u003e\n        \n        \u003cform id=\"formularioAdmision\" novalidate\u003e\n            \u003c!-- Nombre --\u003e\n            \u003cdiv class=\"form-group\"\u003e\n                \u003clabel for=\"nombre\"\u003e\n                    Nombre Completo \u003cspan class=\"required\"\u003e*\u003c/span\u003e\n                \u003c/label\u003e\n                \u003cinput \n                    type=\"text\" \n                    id=\"nombre\" \n                    name=\"nombre\" \n                    placeholder=\"Ej: Juan Pérez García\"\n                    required\n                \u003e\n                \u003cdiv class=\"error\" id=\"errorNombre\"\u003eEl nombre es obligatorio\u003c/div\u003e\n            \u003c/div\u003e\n            \n            \u003c!-- Edad --\u003e\n            \u003cdiv class=\"form-group\"\u003e\n                \u003clabel for=\"edad\"\u003e\n                    Edad \u003cspan class=\"required\"\u003e*\u003c/span\u003e\n                \u003c/label\u003e\n                \u003cinput \n                    type=\"number\" \n                    id=\"edad\" \n                    name=\"edad\" \n                    placeholder=\"Ej: 35\"\n                    min=\"0\"\n                    max=\"150\"\n                    required\n                \u003e\n                \u003cdiv class=\"error\" id=\"errorEdad\"\u003ePor favor ingresa una edad válida (0-150)\u003c/div\u003e\n            \u003c/div\u003e\n            \n            \u003c!-- Alergias --\u003e\n            \u003cdiv class=\"form-group\"\u003e\n                \u003clabel for=\"alergias\"\u003e\n                    Alergias Conocidas \u003cspan class=\"required\"\u003e*\u003c/span\u003e\n                \u003c/label\u003e\n                \u003ctextarea \n                    id=\"alergias\" \n                    name=\"alergias\" \n                    placeholder=\"Ej: Penicilina, Mariscos, Polen\u0026#10;Si no tiene alergias conocidas, escribe ''Ninguna''\"\n                    required\n                \u003e\u003c/textarea\u003e\n                \u003cdiv class=\"error\" id=\"errorAlergias\"\u003ePor favor especifica las alergias o escribe ''Ninguna''\u003c/div\u003e\n            \u003c/div\u003e\n            \n            \u003c!-- Botones --\u003e\n            \u003cdiv class=\"button-group\"\u003e\n                \u003cbutton type=\"submit\" class=\"btn-submit\"\u003eEnviar Formulario\u003c/button\u003e\n                \u003cbutton type=\"reset\" class=\"btn-reset\"\u003eLimpiar\u003c/button\u003e\n            \u003c/div\u003e\n            \n            \u003c!-- Mensaje de éxito --\u003e\n            \u003cdiv class=\"success\" id=\"mensajeExito\"\u003e\n                ✓ Formulario enviado correctamente. Los datos del paciente han sido registrados.\n            \u003c/div\u003e\n        \u003c/form\u003e\n    \u003c/div\u003e\n    \n    \u003cscript\u003e\n        const formulario = document.getElementById(''formularioAdmision'');\n        const campos = {\n            nombre: document.getElementById(''nombre''),\n            edad: document.getElementById(''edad''),\n            alergias: document.getElementById(''alergias'')\n        };\n        \n        const errores = {\n            nombre: document.getElementById(''errorNombre''),\n            edad: document.getElementById(''errorEdad''),\n            alergias: document.getElementById(''errorAlergias'')\n        };\n        \n        const mensajeExito = document.getElementById(''mensajeExito'');\n        \n        // Validación en tiempo real\n        campos.nombre.addEventListener(''input'', function() {\n            if (this.value.trim().length \u003e 0) {\n                errores.nombre.style.display = ''none'';\n            }\n        });\n        \n        campos.edad.addEventListener(''input'', function() {\n            const edad = parseInt(this.value);\n            if (!isNaN(edad) \u0026\u0026 edad \u003e= 0 \u0026\u0026 edad \u003c= 150) {\n                errores.edad.style.display = ''none'';\n            }\n        });\n        \n        campos.alergias.addEventListener(''input'', function() {\n            if (this.value.trim().length \u003e 0) {\n                errores.alergias.style.display = ''none'';\n            }\n        });\n        \n        // Validación del formulario al enviar\n        formulario.addEventListener(''submit'', function(e) {\n            e.preventDefault();\n            \n            let esValido = true;\n            mensajeExito.classList.remove(''show'');\n            \n            // Validar nombre\n            if (campos.nombre.value.trim().length === 0) {\n                errores.nombre.style.display = ''block'';\n                esValido = false;\n            }\n            \n            // Validar edad\n            const edad = parseInt(campos.edad.value);\n            if (isNaN(edad) || edad \u003c 0 || edad \u003e 150) {\n                errores.edad.style.display = ''block'';\n                esValido = false;\n            }\n            \n            // Validar alergias\n            if (campos.alergias.value.trim().length === 0) {\n                errores.alergias.style.display = ''block'';\n                esValido = false;\n            }\n            \n            // Si es válido, mostrar éxito y guardar datos\n            if (esValido) {\n                const datos = {\n                    nombre: campos.nombre.value.trim(),\n                    edad: parseInt(campos.edad.value),\n                    alergias: campos.alergias.value.trim(),\n                    fechaAdmision: new Date().toLocaleString(''es-ES'')\n                };\n                \n                console.log(''Datos registrados:'', datos);\n                \n                // Guardar en localStorage para referencia\n                localStorage.setItem(''ultimaAdmision'', JSON.stringify(datos));\n                \n                // Mostrar mensaje de éxito\n                mensajeExito.classList.add(''show'');\n                \n                // Opcional: limpiar el formulario después de 2 segundos\n                setTimeout(() =\u003e {\n                    formulario.reset();\n                    mensajeExito.classList.remove(''show'');\n                }, 3000);\n            }\n        });\n    \u003c/script\u003e\n\u003c/body\u003e\n\u003c/html\u003e"}]}', '2026-05-07 23:47:31');
