INSERT OR IGNORE INTO 'messages'('id', 'chat_id', 'role', 'content', 'model', 'metadata', 'created_at') VALUES (214, 60, 'user', 'crea un componente medico', 'anthropic/claude-haiku-4-5-20251001', '{}', '2026-05-08 02:13:00');
INSERT OR IGNORE INTO 'messages'('id', 'chat_id', 'role', 'content', 'model', 'metadata', 'created_at') VALUES (215, 60, 'assistant', replace('Necesito más detalles para crear el componente médico adecuado. Tengo disponibles estos componentes especializados:\n\n1. **PatientChart** — Mostrar identidad y signos vitales de un paciente\n2. **MedicationList** — Listar medicamentos activos de un paciente\n3. **AppointmentForm** — Formulario para programar citas\n4. **QuestionnaireForm** — Cuestionario dinámico con preguntas de opción múltiple y texto\n\n¿Cuál te interesa usar o qué tipo de información médica quieres mostrar?\n\nPor ejemplo:\n- ¿Mostrar un perfil de paciente completo con vitales?\n- ¿Listar medicamentos?\n- ¿Crear un formulario para agendar citas?\n- ¿Un cuestionario de evaluación o síntomas?','\n', char(10)), 'anthropic/claude-haiku-4-5-20251001', '{}', '2026-05-08 02:13:06');
