INSERT OR IGNORE INTO 'messages'('id', 'chat_id', 'role', 'content', 'model', 'metadata', 'created_at') VALUES (217, 60, 'assistant', 'Listo. He renderizado un **Patient Chart** en el panel lateral con datos de ejemplo de un paciente. Puedes modificar los datos (nombre, edad, ID, presión arterial, frecuencia cardíaca, temperatura) si necesitas ajustarlo a un caso específico.', 'anthropic/claude-haiku-4-5-20251001', '{"toolCalls":[{"name":"render_component","args":{"name":"PatientChart","placement":"canvas","props":{"age":45,"name":"Carlos Méndez","patientId":"PAT-2026-001","vitals":{"bp":"120/80 mmHg","hr":72,"temp":37.2}}},"result":"rendered component PatientChart (id=art_0834dbe43a9e536f)"}]}', '2026-05-08 02:13:25');
