INSERT OR IGNORE INTO 'messages'('id', 'chat_id', 'role', 'content', 'model', 'metadata', 'created_at') VALUES (234, 62, 'assistant', 'Aquí está el componente de paciente renderizado inline con los datos del paciente Juan García.', 'anthropic/claude-haiku-4-5-20251001', '{"toolCalls":[{"name":"render_component","args":{"name":"PatientChart","placement":"inline","props":{"age":45,"name":"Juan García","patientId":"P12345","vitals":{"bp":"120/80","hr":72,"temp":37.2}}},"result":"rendered component PatientChart (id=art_de32ab776b0c17d9)"}]}', '2026-05-08 02:54:19');
