INSERT OR IGNORE INTO 'artifact_versions'('id', 'artifact_id', 'version', 'content', 'r2_url', 'created_at') VALUES (48, 'e037f216-7dcc-4e3b-b09e-e4c520c5f329', 1, replace('LISTA DE COMPRAS\n================\n\n1. Leche\n2. Pan integral\n3. Huevos (docena)\n4. Manzanas\n5. Pollo (pechuga)\n6. Arroz (1 kg)\n7. Aceite de oliva\n8. Tomates\n9. Queso fresco\n10. Café (molido)\n11. Chocolate\n12. Yogur natural\n','\n', char(10)), '', '2026-05-08 02:55:10');
