INSERT OR IGNORE INTO 'artifact_versions'('id', 'artifact_id', 'version', 'content', 'r2_url', 'created_at') VALUES (38, '787dbe6d-2f7b-41a3-a791-29331e0c90b4', 1, replace('import React from ''react'';\n\nexport default function PatientChart() {\n  const patient = {\n    name: ''Jane Doe'',\n    age: 34,\n    bloodPressure: ''120/80''\n  };\n\n  const medications = [\n    { name: ''Aspirina'', dose: ''100mg'', frequency: ''cada 8h'' },\n    { name: ''Paracetamol'', dose: ''500mg'', frequency: ''cada 6h'' }\n  ];\n\n  return (\n    <div style={{ fontFamily: ''Arial, sans-serif'', padding: ''20px'', maxWidth: ''600px'', margin: ''0 auto'' }}>\n      <h1>Historial del Paciente</h1>\n      \n      <div style={{ border: ''1px solid #ccc'', padding: ''15px'', marginBottom: ''20px'', borderRadius: ''5px'', backgroundColor: ''#f9f9f9'' }}>\n        <h2 style={{ marginTop: 0 }}>Información del Paciente</h2>\n        <p><strong>Nombre:</strong> {patient.name}</p>\n        <p><strong>Edad:</strong> {patient.age} años</p>\n        <p><strong>Presión Arterial:</strong> {patient.bloodPressure} mmHg</p>\n      </div>\n\n      <div style={{ border: ''1px solid #ccc'', padding: ''15px'', borderRadius: ''5px'', backgroundColor: ''#f9f9f9'' }}>\n        <h2 style={{ marginTop: 0 }}>Medicamentos</h2>\n        <table style={{ width: ''100%'', borderCollapse: ''collapse'' }}>\n          <thead>\n            <tr style={{ borderBottom: ''2px solid #333'' }}>\n              <th style={{ textAlign: ''left'', padding: ''8px'' }}>Medicamento</th>\n              <th style={{ textAlign: ''left'', padding: ''8px'' }}>Dosis</th>\n              <th style={{ textAlign: ''left'', padding: ''8px'' }}>Frecuencia</th>\n            </tr>\n          </thead>\n          <tbody>\n            {medications.map((med, idx) => (\n              <tr key={idx} style={{ borderBottom: ''1px solid #ddd'' }}>\n                <td style={{ padding: ''8px'' }}>{med.name}</td>\n                <td style={{ padding: ''8px'' }}>{med.dose}</td>\n                <td style={{ padding: ''8px'' }}>{med.frequency}</td>\n              </tr>\n            ))}\n          </tbody>\n        </table>\n      </div>\n    </div>\n  );\n}','\n', char(10)), '', '2026-05-07 23:45:47');
INSERT OR IGNORE INTO 'artifact_versions'('id', 'artifact_id', 'version', 'content', 'r2_url', 'created_at') VALUES (39, 'cffaacc0-fe9d-417b-a5ec-ff9c86c37f9b', 1, replace('<!DOCTYPE html>\n<html lang="es">\n<head>\n    <meta charset="UTF-8">\n    <meta name="viewport" content="width=device-width, initial-scale=1.0">\n    <title>Formulario de Admisión Hospitalaria</title>\n    <style>\n        * {\n            margin: 0;\n            padding: 0;\n            box-sizing: border-box;\n        }\n        \n        body {\n            font-family: ''Segoe UI'', Tahoma, Geneva, Verdana, sans-serif;\n            background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);\n            min-height: 100vh;\n            display: flex;\n            justify-content: center;\n            align-items: center;\n            padding: 20px;\n        }\n        \n        .container {\n            background: white;\n            border-radius: 10px;\n            box-shadow: 0 10px 40px rgba(0, 0, 0, 0.2);\n            max-width: 600px;\n            width: 100%;\n            padding: 40px;\n        }\n        \n        .header {\n            text-align: center;\n            margin-bottom: 30px;\n            border-bottom: 3px solid #667eea;\n            padding-bottom: 20px;\n        }\n        \n        .header h1 {\n            color: #333;\n            font-size: 28px;\n            margin-bottom: 5px;\n        }\n        \n        .header p {\n            color: #666;\n            font-size: 14px;\n        }\n        \n        .form-group {\n            margin-bottom: 25px;\n        }\n        \n        label {\n            display: block;\n            margin-bottom: 8px;\n            color: #333;\n            font-weight: 600;\n            font-size: 14px;\n        }\n        \n        .required {\n            color: #e74c3c;\n        }\n        \n        input[type="text"],\n        input[type="number"],\n        textarea {\n            width: 100%;\n            padding: 12px;\n            border: 2px solid #ddd;\n            border-radius: 5px;\n            font-size: 14px;\n            font-family: inherit;\n            transition: border-color 0.3s;\n        }\n        \n        input[type="text"]:focus,\n        input[type="number"]:focus,\n        textarea:focus {\n            outline: none;\n            border-color: #667eea;\n            background-color: #f8f9ff;\n        }\n        \n        textarea {\n            resize: vertical;\n            min-height: 100px;\n        }\n        \n        .input-group {\n            display: grid;\n            grid-template-columns: 1fr 1fr;\n            gap: 20px;\n        }\n        \n        .button-group {\n            display: flex;\n            gap: 10px;\n            margin-top: 30px;\n        }\n        \n        button {\n            flex: 1;\n            padding: 12px;\n            border: none;\n            border-radius: 5px;\n            font-size: 16px;\n            font-weight: 600;\n            cursor: pointer;\n            transition: all 0.3s;\n        }\n        \n        .btn-submit {\n            background: #667eea;\n            color: white;\n        }\n        \n        .btn-submit:hover {\n            background: #5568d3;\n            transform: translateY(-2px);\n            box-shadow: 0 5px 15px rgba(102, 126, 234, 0.4);\n        }\n        \n        .btn-reset {\n            background: #e8e8e8;\n            color: #333;\n        }\n        \n        .btn-reset:hover {\n            background: #d0d0d0;\n        }\n        \n        .error {\n            color: #e74c3c;\n            font-size: 12px;\n            margin-top: 5px;\n            display: none;\n        }\n        \n        .success {\n            display: none;\n            background: #d4edda;\n            border: 2px solid #28a745;\n            color: #155724;\n            padding: 15px;\n            border-radius: 5px;\n            margin-top: 20px;\n        }\n        \n        .success.show {\n            display: block;\n        }\n        \n        .info-box {\n            background: #e7f3ff;\n            border-left: 4px solid #667eea;\n            padding: 12px;\n            margin-bottom: 20px;\n            border-radius: 4px;\n            font-size: 13px;\n            color: #333;\n        }\n    </style>\n</head>\n<body>\n    <div class="container">\n        <div class="header">\n            <h1>🏥 Admisión Hospitalaria</h1>\n            <p>Por favor, completa el formulario con la información del paciente</p>\n        </div>\n        \n        <div class="info-box">\n            <strong>Nota:</strong> Los campos marcados con * son obligatorios\n        </div>\n        \n        <form id="formularioAdmision" novalidate>\n            <!-- Nombre -->\n            <div class="form-group">\n                <label for="nombre">\n                    Nombre Completo <span class="required">*</span>\n                </label>\n                <input \n                    type="text" \n                    id="nombre" \n                    name="nombre" \n                    placeholder="Ej: Juan Pérez García"\n                    required\n                >\n                <div class="error" id="errorNombre">El nombre es obligatorio</div>\n            </div>\n            \n            <!-- Edad -->\n            <div class="form-group">\n                <label for="edad">\n                    Edad <span class="required">*</span>\n                </label>\n                <input \n                    type="number" \n                    id="edad" \n                    name="edad" \n                    placeholder="Ej: 35"\n                    min="0"\n                    max="150"\n                    required\n                >\n                <div class="error" id="errorEdad">Por favor ingresa una edad válida (0-150)</div>\n            </div>\n            \n            <!-- Alergias -->\n            <div class="form-group">\n                <label for="alergias">\n                    Alergias Conocidas <span class="required">*</span>\n                </label>\n                <textarea \n                    id="alergias" \n                    name="alergias" \n                    placeholder="Ej: Penicilina, Mariscos, Polen&#10;Si no tiene alergias conocidas, escribe ''Ninguna''"\n                    required\n                ></textarea>\n                <div class="error" id="errorAlergias">Por favor especifica las alergias o escribe ''Ninguna''</div>\n            </div>\n            \n            <!-- Botones -->\n            <div class="button-group">\n                <button type="submit" class="btn-submit">Enviar Formulario</button>\n                <button type="reset" class="btn-reset">Limpiar</button>\n            </div>\n            \n            <!-- Mensaje de éxito -->\n            <div class="success" id="mensajeExito">\n                ✓ Formulario enviado correctamente. Los datos del paciente han sido registrados.\n            </div>\n        </form>\n    </div>\n    \n    <script>\n        const formulario = document.getElementById(''formularioAdmision'');\n        const campos = {\n            nombre: document.getElementById(''nombre''),\n            edad: document.getElementById(''edad''),\n            alergias: document.getElementById(''alergias'')\n        };\n        \n        const errores = {\n            nombre: document.getElementById(''errorNombre''),\n            edad: document.getElementById(''errorEdad''),\n            alergias: document.getElementById(''errorAlergias'')\n        };\n        \n        const mensajeExito = document.getElementById(''mensajeExito'');\n        \n        // Validación en tiempo real\n        campos.nombre.addEventListener(''input'', function() {\n            if (this.value.trim().length > 0) {\n                errores.nombre.style.display = ''none'';\n            }\n        });\n        \n        campos.edad.addEventListener(''input'', function() {\n            const edad = parseInt(this.value);\n            if (!isNaN(edad) && edad >= 0 && edad <= 150) {\n                errores.edad.style.display = ''none'';\n            }\n        });\n        \n        campos.alergias.addEventListener(''input'', function() {\n            if (this.value.trim().length > 0) {\n                errores.alergias.style.display = ''none'';\n            }\n        });\n        \n        // Validación del formulario al enviar\n        formulario.addEventListener(''submit'', function(e) {\n            e.preventDefault();\n            \n            let esValido = true;\n            mensajeExito.classList.remove(''show'');\n            \n            // Validar nombre\n            if (campos.nombre.value.trim().length === 0) {\n                errores.nombre.style.display = ''block'';\n                esValido = false;\n            }\n            \n            // Validar edad\n            const edad = parseInt(campos.edad.value);\n            if (isNaN(edad) || edad < 0 || edad > 150) {\n                errores.edad.style.display = ''block'';\n                esValido = false;\n            }\n            \n            // Validar alergias\n            if (campos.alergias.value.trim().length === 0) {\n                errores.alergias.style.display = ''block'';\n                esValido = false;\n            }\n            \n            // Si es válido, mostrar éxito y guardar datos\n            if (esValido) {\n                const datos = {\n                    nombre: campos.nombre.value.trim(),\n                    edad: parseInt(campos.edad.value),\n                    alergias: campos.alergias.value.trim(),\n                    fechaAdmision: new Date().toLocaleString(''es-ES'')\n                };\n                \n                console.log(''Datos registrados:'', datos);\n                \n                // Guardar en localStorage para referencia\n                localStorage.setItem(''ultimaAdmision'', JSON.stringify(datos));\n                \n                // Mostrar mensaje de éxito\n                mensajeExito.classList.add(''show'');\n                \n                // Opcional: limpiar el formulario después de 2 segundos\n                setTimeout(() => {\n                    formulario.reset();\n                    mensajeExito.classList.remove(''show'');\n                }, 3000);\n            }\n        });\n    </script>\n</body>\n</html>','\n', char(10)), '', '2026-05-07 23:47:31');
INSERT OR IGNORE INTO 'artifact_versions'('id', 'artifact_id', 'version', 'content', 'r2_url', 'created_at') VALUES (40, 'bf68c8e3-b87f-45b3-9f02-cbaac582a2df', 1, replace('# Ecuador: Geografía, Historia y Cultura\n\n## 📍 Ubicación y Geografía\n\nEcuador es un país ubicado en la costa noroeste de América del Sur, sobre la línea ecuatorial (de donde toma su nombre). Limita con Colombia al norte y Perú al sur y este, mientras que el océano Pacífico forma su frontera occidental.\n\n### Regiones Naturales\n\nEl país se divide en cuatro regiones principales:\n\n1. **La Costa** — zona tropical con playas, manglares y ciudades como Guayaquil\n2. **La Sierra** — cordillera de los Andes con volcanes, valles y la capital Quito\n3. **El Oriente** — selva amazónica con biodiversidad única\n4. **Galápagos** — archipiélago insular con fauna endémica de importancia mundial\n\n## 🌍 Biodiversidad\n\nEcuador es uno de los países megadiversos del mundo. A pesar de su tamaño relativamente pequeño, alberga:\n- 10% de todas las especies de plantas del planeta\n- Más de 1,600 especies de aves\n- Especies únicas en Galápagos que inspiraron a Darwin\n\n## 🏛️ Historia\n\n- **Época precolombina**: Dominada por el Imperio Inca\n- **Colonia española** (1534-1822): Integrada como parte de la Audiencia de Quito\n- **Independencia**: Lograda en 1822, siendo parte de Gran Colombia hasta 1830\n- **República**: Desde 1830, con una historia política compleja pero activa\n\n## 💰 Economía\n\n- Moneda: **Dólar estadounidense** (desde 2000)\n- Principales exportaciones: petróleo, bananas, camarones, flores, cacao\n- Sectores clave: agricultura, turismo, industria\n\n## 🎭 Cultura y Tradiciones\n\n- **Idiomas**: Español (oficial) e idiomas indígenas (quechua, shuar, etc.)\n- **Festividades**: Fiestas de Quito, Inti Raymi, Carnaval\n- **Gastronomía**: Ceviche, locro, fritada, canela, llapingachos\n- **Artesanías**: Textiles de Otavalo, cerámica, sombreros de paja toquilla\n\n## 🏙️ Ciudades Principales\n\n- **Quito** — capital, ubicada a 2,850 metros de altitud\n- **Guayaquil** — mayor ciudad y puerto principal\n- **Cuenca** — importante centro cultural y patrimonial\n- **Ambato**, **Riobamba**, **Loja** — ciudades andinas significativas\n\n## 🌱 Potencial Turístico\n\nEcuador atrae turismo por:\n- Las Galápagos (patrimonio natural de la humanidad)\n- La riqueza de la Amazonía\n- Los volcanes y montañas de la Sierra\n- Su diversidad cultural y arqueológica\n','\n', char(10)), '', '2026-05-08 00:37:09');
INSERT OR IGNORE INTO 'artifact_versions'('id', 'artifact_id', 'version', 'content', 'r2_url', 'created_at') VALUES (41, '4e020346-23d7-4ed3-b588-eb7bfe95daab', 1, replace('# Ecuador: El Corazón de Sudamérica\n\n## Introducción\n\nEcuador es un país ubicado en la costa noroeste de Sudamérica que, a pesar de su pequeño tamaño, posee una riqueza natural y cultural extraordinaria. Con una población de aproximadamente 18 millones de habitantes, es uno de los países más biodiversos del planeta y ofrece una fascinante mezcla de tradiciones ancestrales, modernidad y paisajes de ensueño.\n\n## Geografía y Ubicación\n\nEcuador se encuentra estratégicamente ubicado sobre la línea ecuatorial, de donde toma su nombre. Con una superficie de 283,561 km², es el país más pequeño de Sudamérica después de Surinam y Guyana. A pesar de esto, su geografía es extraordinariamente diversa.\n\nEl país se divide en cuatro regiones naturales distintas:\n\n- **La Costa**: Caracterizada por playas tropicales, manglares y ciudades portuarias como Guayaquil.\n- **La Sierra**: Una cadena montañosa que forma parte de los Andes, con volcanes activos y ciudades como Quito.\n- **La Amazonía**: La región oriental, rica en biodiversidad y hogar de comunidades indígenas.\n- **Galápagos**: Un archipiélago insular único, declarado Patrimonio de la Humanidad.\n\n## Biodiversidad: Un Tesoro Mundial\n\nEcuador es considerado uno de los diecisiete países megadiversos del mundo. A pesar de representar apenas el 0.06% de la superficie terrestre, alberga el 10% de toda la vida silvestre del planeta.\n\nEsta riqueza incluye:\n- Más de 1,600 especies de aves\n- Aproximadamente 300 especies de anfibios\n- Miles de especies de plantas y flores\n- Jaguares, anacondas, delfines de río y otras especies emblemáticas\n\nLas Islas Galápagos, en particular, son un laboratorio viviente de evolución donde se encuentran especies endémicas que inspiraron a Charles Darwin en el desarrollo de su teoría de la selección natural.\n\n## Historia y Cultura\n\n### Herencia Prehispánica\n\nAntes de la conquista española, Ecuador fue el hogar del Imperio Inca. La ciudad de Quito fue una importante capital regional, y aún hoy se pueden observar vestigios de esta época en sitios arqueológicos y en la arquitectura colonial que posteriormente se construyó.\n\n### Época Colonial y Republicana\n\nLa colonización española transformó la región, dejando un legado que aún pervive en la arquitectura, la religión y las tradiciones. Quito es declarada Patrimonio de la Humanidad por la UNESCO debido a su centro histórico perfectamente conservado, con iglesias, plazas y edificios coloniales que transportan al visitante siglos atrás.\n\nEcuador se independizó en 1809, siendo uno de los primeros países latinoamericanos en proclamar su independencia, aunque la consolidación definitiva ocurrió en 1822.\n\n### Diversidad Étnica\n\nEcuador es profundamente multicultural. Su población incluye mestizos, indígenas quichuas, afrodescendientes y caucásicos. Cada grupo aporta sus propias tradiciones, lenguas y costumbres. El quichua es ampliamente hablado en la región andina, mientras que el español es el idioma oficial.\n\n## Economía\n\nLa economía ecuatoriana se basa principalmente en:\n\n**Petróleo**: Ha sido históricamente la principal fuente de divisas, aunque las fluctuaciones de precios internacionales generan volatilidad económica.\n\n**Agricultura**: El cacao, plátano, café y flores ecuatorianas son exportadas a mercados internacionales. Ecuador es el mayor exportador de cacao del mundo.\n\n**Turismo**: El ecoturismo, especialmente en Galápagos y la Amazonía, genera ingresos significativos.\n\n**Manufactura**: La producción textil y de alimentos también contribuye a la economía nacional.\n\n## Destinos Turísticos\n\n### Quito\nLa capital, ubicada a 2,850 metros de altura, es una ciudad vibrante con un centro histórico fascinante, museos de clase mundial y una gastronomía exquisita.\n\n### Galápagos\nUn destino imprescindible para naturalistas y aventureros, donde se pueden observar especies únicas en su hábitat natural.\n\n### La Amazonía\nOfrece experiencias de inmersión en la naturaleza y contacto con comunidades indígenas que han preservado sus formas de vida ancestrales.\n\n### Cuenca\nUna joya colonial en la sierra sur, conocida por su arquitectura, artesanías y ambiente bohemio.\n\n## Desafíos Contemporáneos\n\nComo muchos países latinoamericanos, Ecuador enfrenta desafíos importantes:\n\n- **Inseguridad**: El crimen organizado relacionado con el tráfico de drogas ha aumentado en años recientes.\n- **Desigualdad económica**: A pesar de sus recursos, persisten brechas significativas entre ricos y pobres.\n- **Cambio climático**: Afecta la biodiversidad y la producción agrícola.\n- **Acceso a servicios**: En zonas rurales e indígenas, el acceso a educación y salud sigue siendo limitado.\n\n## Conclusión\n\nEcuador es un país de contrastes y contradicciones: pequeño en tamaño pero gigante en biodiversidad, rico en recursos naturales pero enfrentando desigualdad, antiguo en historia pero joven en desarrollo. Su gente, resiliente y orgullosa de su herencia, sigue trabajando para construir un futuro que honre su pasado mientras abraza el progreso.\n\nYa sea por sus paisajes impresionantes, su rica cultura o su extraordinaria naturaleza, Ecuador merece un lugar especial en el corazón de quien lo visita o lo estudia.\n\n---\n\n**Palabra clave**: Ecuador es mucho más que un punto geográfico en el mapa; es un microcosmos del planeta donde la naturaleza, la historia y la humanidad convergen de manera única y memorable.\n','\n', char(10)), '', '2026-05-08 00:44:18');
INSERT OR IGNORE INTO 'artifact_versions'('id', 'artifact_id', 'version', 'content', 'r2_url', 'created_at') VALUES (42, 'ca940b78-2728-4012-b7d1-0acdb1a93f24', 1, replace('# Geografía de Ecuador\n\n## Ubicación y Regiones Naturales\n\nEcuador es un país ubicado en la región noroccidental de **América del Sur**, caracterizado por una geografía extraordinariamente diversa comprimida en un territorio relativamente pequeño. Su relieve es dominado por la **Cordillera de los Andes**, que atraviesa el país de norte a sur dividiéndolo en tres regiones naturales claramente definidas:\n\n- **La Costa** — región tropical con acceso al océano Pacífico\n- **La Sierra** — región andina de altas montañas y volcanes\n- **El Oriente Amazónico** — región oriental selvática\n\n## Volcanes y Cordilleras\n\nLa región de la Sierra alberga algunos de los volcanes más importantes del continente, incluyendo el **Cotopaxi**, considerado uno de los volcanes más altos del mundo activo, y el **Chimborazo**, la cumbre más elevada de Ecuador. Estos volcanes forman parte de la cadena montañosa andina y son características prominentes del paisaje ecuatoriano.\n\n## Sistemas Hidrográficos\n\nEl país posee una red hidrográfica importante constituida por ríos que desembocan en dos grandes sistemas:\n\n- **Sistema atlántico** — a través del Amazonas hacia el Atlántico\n- **Sistema pacífico** — hacia el océano Pacífico\n\nEl **río Amazonas** es fundamental para la región oriental del país, proporcionando una biodiversidad incomparable.\n\n## Variabilidad Climática\n\nEl clima en Ecuador varía *dramáticamente* según la altitud y la región:\n\n- **Costa:** tropical húmeda con temperaturas cálidas\n- **Sierra:** clima templado a frío según la elevación\n- **Región amazónica:** tropical húmedo con abundantes precipitaciones\n\nEsta variabilidad climática genera una **diversidad biológica excepcional**, convirtiendo a Ecuador en uno de los países más biodiversos del mundo por unidad de superficie.\n\n## Islas Galápagos\n\nLas **Islas Galápagos**, ubicadas en el océano Pacífico a más de 1000 kilómetros de la costa continental, forman parte del territorio ecuatoriano y representan un ecosistema único de importancia mundial para la conservación.\n','\n', char(10)), '', '2026-05-08 01:01:08');
INSERT OR IGNORE INTO 'artifact_versions'('id', 'artifact_id', 'version', 'content', 'r2_url', 'created_at') VALUES (43, '9c1d2638-14ee-41cc-b5f7-ee37255cca66', 1, replace('# Ubicación de Ecuador\n\n## Posición Geográfica\n\nEcuador se localiza en la **línea ecuatorial** (de donde obtiene su nombre) en la región noroccidental de América del Sur. Geográficamente, se sitúa entre las latitudes **1°27'' N y 5°01'' S**, y entre las longitudes **75°11'' y 81°00'' O**, ocupando una posición estratégica en el trópico americano.\n\n## Límites Fronterizos\n\nEl país limita con:\n\n- **Norte:** Colombia\n- **Sur y Este:** Perú\n- **Oeste:** Océano Pacífico\n- **Este:** Cuenca amazónica\n\nEsta configuración lo posiciona como **puente entre la región andina y la amazónica**, y entre Sudamérica y Centroamérica.\n\n## Características Territoriales\n\nSu ubicación ecuatorial le confiere características climáticas y ecológicas únicas. El territorio continental ecuatoriano cubre aproximadamente **283,561 kilómetros cuadrados**, pero si se incluyen las **Islas Galápagos** (un archipiélago ubicado a más de 1000 kilómetros en el océano Pacífico), su jurisdicción se extiende significativamente hacia el oeste.\n\n## Importancia Estratégica\n\nEn el contexto suramericano, Ecuador representa la **puerta noroeste del continente**, siendo un punto crucial de conexión comercial, cultural y ecológica. Su localización le permite ejercer soberanía sobre territorios tanto continentales como insulares, abarcando ecosistemas que van desde el Pacífico tropical hasta las alturas andinas y la selva amazónica.\n\nEsta posición geográfica privilegiada ha moldeado su historia, economía y su importancia ambiental global.\n','\n', char(10)), '', '2026-05-08 01:01:08');
